import os
import shutil
import random

# --- CONFIGURATION ---
DATASET_DIR = r"D:\Projects\HACK2SKILL\Synthrescue\dataset"
SPLIT_RATIO = 0.8  # 80% for training, 20% for validation

def split_dataset():
    images_dir = os.path.join(DATASET_DIR, "images")
    labels_dir = os.path.join(DATASET_DIR, "labels")

    # Create train and val subdirectories
    for folder in ["train", "val"]:
        os.makedirs(os.path.join(images_dir, folder), exist_ok=True)
        os.makedirs(os.path.join(labels_dir, folder), exist_ok=True)

    # Grab all raw images generated by Blender
    all_images = [f for f in os.listdir(images_dir) if f.endswith(('.png', '.jpg', '.jpeg')) and os.path.isfile(os.path.join(images_dir, f))]
    
    # Shuffle for randomness
    random.shuffle(all_images)

    # Calculate split point
    split_index = int(len(all_images) * SPLIT_RATIO)
    train_images = all_images[:split_index]
    val_images = all_images[split_index:]

    def move_files(file_list, split_name):
        count = 0
        for img_name in file_list:
            base_name = os.path.splitext(img_name)[0]
            lbl_name = base_name + ".txt"

            src_img = os.path.join(images_dir, img_name)
            src_lbl = os.path.join(labels_dir, lbl_name)

            dst_img = os.path.join(images_dir, split_name, img_name)
            dst_lbl = os.path.join(labels_dir, split_name, lbl_name)

            # Move image and label into train/val folders
            if os.path.exists(src_img):
                shutil.move(src_img, dst_img)
            if os.path.exists(src_lbl):
                shutil.move(src_lbl, dst_lbl)
            count += 1
        return count

    print("🚀 Splitting synthetic dataset into train/val...")
    train_count = move_files(train_images, "train")
    val_count = move_files(val_images, "val")

    print(f"✅ Split Complete! Train: {train_count} images | Val: {val_count} images")

if __name__ == "__main__":
    split_dataset()